$ErrorActionPreference="Stop";$Root=Split-Path -Parent $MyInvocation.MyCommand.Path;$Port=if($args.Count -gt 0 -and $args[0]){[string]$args[0]}else{"46020"};$LogDir=Join-Path $Root "logs";$StateDir=Join-Path $Root "state";$OutLog=Join-Path $LogDir "startup-ui.out.log";$ErrLog=Join-Path $LogDir "startup-ui.err.log";$PidFile=Join-Path $StateDir "startup-ui-pids.json";New-Item -ItemType Directory -Force -Path $LogDir,$StateDir|Out-Null;function Test-HttpOk($Uri){try{$r=Invoke-WebRequest -UseBasicParsing -Uri $Uri -TimeoutSec 3;return @{ok=$true;status=$r.StatusCode}}catch{return @{ok=$false;error=$_.Exception.Message}}};function Get-PortListenerPid($PortValue){Get-NetTCPConnection -LocalPort ([int]$PortValue) -State Listen -ErrorAction SilentlyContinue|Select-Object -ExpandProperty OwningProcess -Unique -First 1};$healthUrl="http://127.0.0.1:$Port/api/snapshot";$existing=Test-HttpOk $healthUrl;if($existing.ok){Write-Host "Startup UI already running: http://127.0.0.1:$Port PID=$(Get-PortListenerPid $Port)";return};$process=Start-Process -FilePath "node.exe" -ArgumentList @("server.js",$Port) -WorkingDirectory $Root -RedirectStandardOutput $OutLog -RedirectStandardError $ErrLog -WindowStyle Hidden -PassThru;Start-Sleep -Milliseconds 900;$health=Test-HttpOk $healthUrl;@{startedAt=(Get-Date).ToString("o");root=$Root;port=$Port;pid=$process.Id;url="http://127.0.0.1:$Port";logs=@{stdout=$OutLog;stderr=$ErrLog}}|ConvertTo-Json -Depth 5|Set-Content -LiteralPath $PidFile -Encoding UTF8;if($health.ok){Write-Host "Startup UI started detached: http://127.0.0.1:$Port PID=$($process.Id)"}else{Write-Host "Startup UI start requested, but health check failed: $($health.error)";Write-Host "PID=$($process.Id) Logs: $OutLog ; $ErrLog"}
